import { Linking } from 'react-native';
import React, { useState, useEffect } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

function ProfileScreen() {
  const navigation = useNavigation();
  const profileId = Linking.parse(getUrl()).params.id;

  return (
    <View>
      <Text>Profile Screen</Text>
      <Text>ID: {profileId}</Text>
      <Button title="Go back" onPress={() => navigation.goBack()} />
    </View>
  );
}

function PaymentConfirmScreen() {
  const paymentMethod = Linking.parse(getUrl()).params.payment;

  return (
    <View>
      <Text>Payment Confirm Screen</Text>
      <Text>Payment Method: {paymentMethod}</Text>
      <Button title="Go back" onPress={() => navigation.goBack()} />
    </View>
  );
}

function getUrl() {
  const url = Linking.parse(getUrl());
  return url;
}

function App() {
  return (
    <NavigationContainer>
      <Stack.Navigator>
        <Stack.Screen name="ProfileScreen" component={ProfileScreen} options={{ title: 'Profile' }} />
        <Stack.Screen name="PaymentConfirmScreen" component={PaymentConfirmScreen} options={{ title: 'Confirm Payment' }} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

function getParams(url) {
  const parsedUrl = new URL(url);
  return Object.keys(parsedUrl.searchParams).reduce((params, key) => {
    params[key] = parsedUrl.searchParams.get(key);
    return params;
  }, {});
}